import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import Layout from './components/layout/Layout';
import PrivateRoute from './components/layout/PrivateRoute';

// Pages
import Login from './pages/Auth/Login';
import Dashboard from './pages/Auth/Dashboard';
import BookingList from './pages/Bookings/BookingList';
import BookingForm from './pages/Bookings/BookingForm';
import BookingApproval from './pages/Bookings/BookingApproval';
import ResourceList from './pages/Resources/ResourceList';

function AppRoutes() {
  const { isAdmin } = useAuth();

  return (
    <Routes>
      <Route path="/login" element={<Login />} />
      <Route element={<PrivateRoute />}>
        <Route element={<Layout />}>
          <Route path="/" element={<Navigate to={isAdmin() ? '/admin/dashboard' : '/bookings'} />} />
          {isAdmin() && (
            <Route path="/admin/dashboard" element={<Dashboard />} />
          )}
          <Route path="/bookings" element={<BookingList />} />
          <Route path="/bookings/new" element={<BookingForm />} />
          <Route path="/rooms" element={<ResourceList />} />
          {isAdmin() && (
            <Route path="/admin/bookings" element={<BookingApproval />} />
          )}
        </Route>
      </Route>
    </Routes>
  );
}

function App() {
  return (
    <AuthProvider>
      <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
        <AppRoutes />
      </Router>
    </AuthProvider>
  );
}

export default App;
